const VOWELS = new Set(['a', 'e', 'i', 'o', 'u']);

/**
 * Checks if a character is a vowel.
 * @param {string} char
 * @returns {boolean}
 */
function isVowel(char) {
    return VOWELS.has(char);
}

/**
 * Rearranges only the vowels in the string s according to specific criteria.
 * @param {string} s The input string.
 * @returns {string} The modified string.
 */
function solve(s) {
    const n = s.length;

    // 1. Collect necessary data: counts, first index, and indices of all vowels.
    const counts = new Map();
    const firstIndex = new Map();
    const vowelIndices = [];

    for (let i = 0; i < n; i++) {
        const char = s[i];
        if (isVowel(char)) {
            vowelIndices.push(i);

            // Count frequency
            counts.set(char, (counts.get(char) || 0) + 1);

            // Record first index
            if (!firstIndex.has(char)) {
                firstIndex.set(char, i);
            }
        }
    }

    // 2. Get unique vowels found and prepare for sorting.
    const uniqueVowels = Array.from(counts.keys());

    // 3. Sort unique vowels based on criteria:
    // a) Frequency (descending)
    // b) First appearance index (ascending)
    uniqueVowels.sort((v1, v2) => {
        const count1 = counts.get(v1);
        const count2 = counts.get(v2);

        // Sort by frequency descending
        if (count1 !== count2) {
            return count2 - count1;
        }

        // Tie-breaker: sort by first index ascending
        const index1 = firstIndex.get(v1);
        const index2 = firstIndex.get(v2);
        return index1 - index2;
    });

    // 4. Construct the final ordered sequence of all vowels.
    const orderedVowels = [];
    for (const vowel of uniqueVowels) {
        const count = counts.get(vowel);
        for (let i = 0; i < count; i++) {
            orderedVowels.push(vowel);
        }
    }

    // 5. Reconstruct the string.
    const result = Array(n);
    let vowelPointer = 0;

    for (let i = 0; i < n; i++) {
        if (isVowel(s[i])) {
            // Replace with the next vowel from the sorted sequence
            result[i] = orderedVowels[vowelPointer];
            vowelPointer++;
        } else {
            // Consonants remain in place
            result[i] = s[i];
        }
    }

    return result.join('');
}

