package main

import (
	"sort"
)

func isVowel(char rune) bool {
	switch char {
	case 'a', 'e', 'i', 'o', 'u':
		return true
	default:
		return false
	}
}

func solve(s string) string {
	runes := []rune(s)
	n := len(runes)

	counts := make(map[rune]int)
	firstIndex := make(map[rune]int)

	// 1. Collect necessary data: counts and first index.
	for i, char := range runes {
		if isVowel(char) {
			counts[char]++
			if _, ok := firstIndex[char]; !ok {
				firstIndex[char] = i
			}
		}
	}

	// 2. Get unique vowels found.
	uniqueVowels := make([]rune, 0, len(counts))
	for v := range counts {
		uniqueVowels = append(uniqueVowels, v)
	}

	// 3. Sort unique vowels based on criteria:
	// a) Frequency (descending)
	// b) First appearance index (ascending)
	sort.Slice(uniqueVowels, func(i, j int) bool {
		v1 := uniqueVowels[i]
		v2 := uniqueVowels[j]

		count1 := counts[v1]
		count2 := counts[v2]

		// Sort by frequency descending (count2 > count1 means v2 comes before v1)
		if count1 != count2 {
			return count1 > count2
		}

		// Tie-breaker: sort by first index ascending
		index1 := firstIndex[v1]
		index2 := firstIndex[v2]
		return index1 < index2
	})

	// 4. Construct the final ordered sequence of all vowels.
	orderedVowels := make([]rune, 0)
	for _, v := range uniqueVowels {
		count := counts[v]
		for i := 0; i < count; i++ {
			orderedVowels = append(orderedVowels, v)
		}
	}

	// 5. Reconstruct the string.
	resultRunes := make([]rune, n)
	vowelPointer := 0

	for i, char := range runes {
		if isVowel(char) {
			// Replace with the next vowel from the sorted sequence
			resultRunes[i] = orderedVowels[vowelPointer]
			vowelPointer++
		} else {
			// Consonants remain in place
			resultRunes[i] = char
		}
	}

	return string(resultRunes)
}
